  `serial` text NOT NULL COMMENT '序列号',
  `total` decimal(12,4) NOT NULL COMMENT '总成本',
  `data` varchar(256) NOT NULL COMMENT '备注信息',
  PRIMARY KEY (`id`),
  KEY `pid` (`pid`),
  KEY `goods` (`goods`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='其它入库单详情';


