DROP TABLE IF EXISTS `is_mould`;
CREATE TABLE `is_mould` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(32) NOT NULL COMMENT '模板名称',
  `key` varchar(32) NOT NULL COMMENT '模板标识',
  `sort` int(11) DEFAULT '0' COMMENT '模板排序',
  `source` text NOT NULL COMMENT '数据源',
  `code` text NOT NULL COMMENT '模板代码',
  `data` varchar(256) NOT NULL COMMENT '备注信息',
  PRIMARY KEY (`id`),
  KEY `key` (`key`),
  KEY `name` (`name`),
  KEY `sort` (`sort`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='打印模板';

