  `examine` tinyint(1) DEFAULT '0' COMMENT '审核状态[0:未审核|1:已审核]',
  `cse` tinyint(1) DEFAULT NULL COMMENT '费用状态[0:未结算|1:部分结算|2:已结算|3:无需结算]',
  `user` int(11) NOT NULL COMMENT '制单人',
