DROP TABLE IF EXISTS `is_swap_info`;
CREATE TABLE `is_swap_info` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `pid` int(11) NOT NULL COMMENT '所属ID',
  `goods` int(11) NOT NULL COMMENT '所属商品',
