  KEY `frame` (`frame`),
  KEY `tel` (`tel`),
  KEY `role` (`role`),
  KEY `user` (`user`),
  KEY `expire` (`expire`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='用户';

